import{_ as a,o as e,c as l,a2 as i}from"./chunks/framework.DIMps2S2.js";const p=JSON.parse('{"title":"股单","description":"","frontmatter":{"layout":"doc","sidebar":true},"headers":[],"relativePath":"app-guide/stock-notes.md","filePath":"zh-CN/app-guide/stock-notes.md"}'),r={name:"app-guide/stock-notes.md"};function o(d,t,n,s,h,c){return e(),l("div",null,[...t[0]||(t[0]=[i('<h1 id="股单" tabindex="-1">股单 <a class="header-anchor" href="#股单" aria-label="Permalink to &quot;股单&quot;">​</a></h1><p>股单是由平台官方或用户创建的主题股票组合（类似投资主题篮子）。关注股单后可一键查看组合内所有标的的实时表现。入口在 App 底部导航「关注」Tab 的「股单」子页。</p><h2 id="股单与自选的区别" tabindex="-1">股单与自选的区别 <a class="header-anchor" href="#股单与自选的区别" aria-label="Permalink to &quot;股单与自选的区别&quot;">​</a></h2><table tabindex="0"><thead><tr><th></th><th>自选</th><th>股单</th></tr></thead><tbody><tr><td>创建者</td><td>用户本人</td><td>平台官方或其他用户</td></tr><tr><td>可编辑</td><td>可自由增删标的</td><td>只能关注/取消关注，不可编辑内容</td></tr><tr><td>用途</td><td>个人持仓跟踪</td><td>主题投资参考</td></tr></tbody></table><h2 id="股单展示内容" tabindex="-1">股单展示内容 <a class="header-anchor" href="#股单展示内容" aria-label="Permalink to &quot;股单展示内容&quot;">​</a></h2><ul><li>股单名称（如「AI 算力核心」「港股机器人概念」）</li><li>涵盖标的数量</li><li>整体涨跌幅</li><li>组合内各标的当日涨跌排列</li></ul><h2 id="官方股单示例" tabindex="-1">官方股单示例 <a class="header-anchor" href="#官方股单示例" aria-label="Permalink to &quot;官方股单示例&quot;">​</a></h2><p>官方股单由平台运营维护，成分股会随主题变化而调整；用户创建的股单由创建者自行维护。平台定期维护主题股单，覆盖热门投资方向：</p><ul><li>AI 算力核心</li><li>AI 软件应用</li><li>港股机器人概念</li><li>港股光伏</li><li>港股创新药</li><li>内存与存储</li><li>韩国市场相关股</li><li>SpaceX 相关 / OpenClaw 相关</li></ul><h2 id="操作" tabindex="-1">操作 <a class="header-anchor" href="#操作" aria-label="Permalink to &quot;操作&quot;">​</a></h2><ul><li><strong>关注</strong>：点击股单详情页的关注按钮，后续在「关注」Tab 可看到该股单动态；关注股单与关注个股不同——关注股单后，该股单整体动态（调仓、成分股异动）出现在「动态 → 关注」Feed，关注个股则在自选列表跟踪单只行情</li><li><strong>添加至自选</strong>：在股单内找到感兴趣的标的，单独添加至个人自选</li><li><strong>排序</strong>：可按「添加时间」或「当日涨跌」对股单内标的排序</li><li><strong>创建自定义股单</strong>：部分账户等级支持，在股单页面点击右上角创建入口操作</li></ul><h2 id="引用此页面的文档" tabindex="-1">引用此页面的文档 <a class="header-anchor" href="#引用此页面的文档" aria-label="Permalink to &quot;引用此页面的文档&quot;">​</a></h2><ul><li><a href="/wiki/app-guide">App 导览</a></li></ul>',13)])])}const _=a(r,[["render",o]]);export{p as __pageData,_ as default};
